def get_total_number_of_sequences(n, m):
    # 初始化一个二维数组，用于存储每个位置的可能序列数
    dp = [[0] * (m + 1) for _ in range(n + 1)]

    # 初始化第一行和第一列
    for i in range(m + 1):
        dp[1][i] = 1

    # 动态规划
    for i in range(2, n + 1):
        for j in range(1, m + 1):
            # 如果当前位置的值小于或等于 2 * (前一个位置的值 - 1)，则可以选择前一个位置的值
            if j <= 2 * (j - 1):
                dp[i][j] = dp[i - 1][j - 1]
            # 如果当前位置的值大于或等于 2 * (前一个位置的值 - 1)，则可以选择前一个位置的值或前两个位置的值
            else:
                dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j - 2]

    # 返回最后一个位置的可能序列数
    return dp[n][m]
```

