def check_date(year, month, day):
    # 检查年份是否合法
    if year < 1:
        return False

    # 检查月份是否合法
    if month < 1 or month > 12:
        return False

    # 检查天数是否合法
    if day < 1:
        return False

    # 检查闰年
    if (year % 4 == 0 and year % 100 != 0) or year % 400 == 0:
        # 闰年
        if month in [1, 3, 5, 7, 8, 10, 12]:
            # 31天的月份
            if day > 31:
                return False
        elif month == 2:
            # 2月
            if day > 29:
                return False
        else:
            # 30天的月份
            if day > 30:
                return False
    else:
        # 平年
        if month in [1, 3, 5, 7, 8, 10, 12]:
            # 31天的月份
            if day > 31:
                return False
        elif month == 2:
            # 2月
            if day > 28:
                return False
        else:
            # 30天的月份
            if day > 30:
                return False

    # 如果通过了所有检查，日期是合法的
    return True
