def factorial(n):
    """
    计算n的阶乘
    """
    if n == 0:
        return 1
    else:
        return n * factorial(n-1)

def binomial_coefficient(n, k):
    """
    计算n中取k的二项式系数
    """
    return factorial(n) / (factorial(k) * factorial(n-k))

def sum_of_squares_of_binomial_coefficients(n):
    """
    计算n中取k的二项式系数的平方和
    """
    total = 0
    for k in range(n+1):
        total += binomial_coefficient(n, k) ** 2
    return total

