def concatenate_nested(tuple1, tuple2):
    # 首先，我们需要检查输入的两个元组是否都是元组类型
    if not isinstance(tuple1, tuple) or not isinstance(tuple2, tuple):
        raise ValueError("输入的两个参数必须都是元组类型")

    # 然后，我们需要检查两个元组的结构是否都是嵌套的
    def is_nested_tuple(t):
        # 如果元组中有非元组元素，则认为不是嵌套元组
        return all(isinstance(x, tuple) for x in t)

    if not is_nested_tuple(tuple1) or not is_nested_tuple(tuple2):
        raise ValueError("输入的两个参数必须都是嵌套元组")

    # 最后，我们可以通过将两个元组的元素合并起来来实现嵌套元组的连接
    # 我们使用列表推导式来实现这一点
    return tuple(x for pair in zip(tuple1, tuple2) for x in pair)
