def diff_even_odd(lst):
    # 检查列表是否为空
    if not lst:
        return None

    # 初始化变量，用于存储偶数和奇数的值
    even_num = None
    odd_num = None

    # 遍历列表，找出第一个偶数和第一个奇数
    for num in lst:
        # 如果当前数字是偶数
        if num % 2 == 0:
            # 如果之前找到的偶数是None（即还没有找到偶数），则更新偶数的值
            if even_num is None:
                even_num = num
        # 如果当前数字是奇数
        else:
            # 如果之前找到的奇数是None（即还没有找到奇数），则更新奇数的值
            if odd_num is None:
                odd_num = num

    # 如果找到了偶数和奇数，则返回它们的差值
    if even_num is not None and odd_num is not None:
        return even_num - odd_num
    # 如果找到了偶数但没有找到奇数，则返回偶数的负值
    elif even_num is not None:
        return -even_num
    # 如果找到了奇数但没有找到偶数，则返回奇数的负值
    elif odd_num is not None:
        return -odd_num
    # 如果列表中既没有偶数也没有奇数，则返回None
    else:
        return None
