def mul_even_odd(lst):
    # 检查列表是否为空
    if not lst:
        return None

    # 初始化变量，用于存储偶数和奇数的数量
    even_count = 0
    odd_count = 0

    # 遍历列表，统计偶数和奇数的数量
    for num in lst:
        if num % 2 == 0:
            even_count += 1
        else:
            odd_count += 1

    # 确定第一个偶数和第一个奇数的索引
    first_even_index = None
    first_odd_index = None
    for i, num in enumerate(lst):
        if num % 2 == 0:
            first_even_index = i
            break
        else:
            first_odd_index = i

    # 确定第一个偶数和第一个奇数的值
    first_even = None
    first_odd = None
    if first_even_index is not None:
        first_even = lst[first_even_index]
    if first_odd_index is not None:
        first_odd = lst[first_odd_index]

    # 计算第一个偶数和第一个奇数的乘积
    if first_even is not None and first_odd is not None:
        return first_even * first_odd
    elif first_even is not None:
        return first_even
    elif first_odd is not None:
        return first_odd
    else:
        return None
```

