def add_dict(dict1, dict2):
    # 检查输入是否为字典
    if not isinstance(dict1, dict) or not isinstance(dict2, dict):
        raise ValueError("输入必须为字典")

    # 创建一个新的字典来存储结果
    result = {}

    # 将 dict1 中的键值对添加到结果字典中
    for key, value in dict1.items():
        result[key] = value

    # 将 dict2 中的键值对添加到结果字典中
    for key, value in dict2.items():
        # 如果结果字典中已经存在该键，则将两个值相加
        if key in result:
            result[key] += value
        # 如果结果字典中不存在该键，则直接添加
        else:
            result[key] = value

    return result
```

