def first_repeated_word(s):
    # 将字符串转换为小写，去掉所有非字母数字的字符，并分割成列表
    words = ''.join(e for e in s if e.isalnum() or e.isspace()).lower().split()

    # 使用字典来存储每个单词的出现次数
    word_count = {}
    for word in words:
        # 如果单词已经在字典中，则增加计数，否则添加到字典中
        if word in word_count:
            word_count[word] += 1
        else:
            word_count[word] = 1

    # 遍历字典，找到第一个出现次数大于 1 的单词
    for word, count in word_count.items():
        if count > 1:
            return word

    # 如果没有找到重复的单词，则返回 None
    return None
```

