def common_in_nested_lists(nested_lists):
    # 首先，我们需要将所有嵌套列表中的元素都提取出来，放入一个集合中
    all_elements = set()
    for lst in nested_lists:
        for element in lst:
            all_elements.add(element)

    # 然后，我们需要找到每个嵌套列表中出现的元素的数量
    element_counts = {}
    for lst in nested_lists:
        for element in lst:
            if element in element_counts:
                element_counts[element] += 1
            else:
                element_counts[element] = 1

    # 最后，我们需要找出所有出现次数大于 1 的元素
    common_elements = [element for element, count in element_counts.items() if count > 1]

    return common_elements

# 测试函数
