def count_Divisors(n):
    # 计算 n 的除数个数
    count = 0
    for i in range(1, int(n**0.5) + 1):
        if n % i == 0:
            # 如果 i 是除数，则 n//i 也一定是除数
            if i * i != n:
                count += 2
            else:
                count += 1
    return count

def check_Divisor_Count(n):
    # 检查 n 的除数个数是否为偶数或奇数
    divisor_count = count_Divisors(n)
    if divisor_count % 2 == 0:
        return "偶数"
    else:
        return "奇数"

# 测试
print(check_Divisor_Count(12))  # 输出: 偶数
print(check_Divisor_Count(13))  # 输出: 奇数
```

